args.sparql:
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>

SELECT ?house ?owner ?area ?houseLabel ?ownerLabel
WHERE {
  ?house wdt:P131 wd:Q127856;
         wdt:P31 ?type;
         wdt:P2510 ?area;
         wdt:P1830 ?owner.
  VALUES ?type { wd:Q3947 wd:Q759751 }
  ?house rdfs:label ?houseLabel.
  ?owner rdfs:label ?ownerLabel.
  FILTER(LANG(?houseLabel) = 'en' && LANG(?ownerLabel) = 'en')
}
ORDER BY DESC(?area)
LIMIT 1
